#!/bin/bash
# StreamForge Update Script - run INSIDE the container
# curl -fsSL https://raw.githubusercontent.com/rpoltera/streamforge/main/streamforge-update.sh | bash
set -euo pipefail
export LANG=en_US.UTF-8

YW='\033[33m'; GN='\033[1;92m'; RD='\033[01;31m'; CL='\033[m'
BFR="\\r\\033[K"
CM="${GN}✓${CL}"; TAB="  "
msg_info() { printf "${TAB}${YW}[ .. ]${CL} %s..." "$1"; }
msg_ok()   { printf "${BFR}${TAB}${CM} %s\n" "$1"; }

INSTALL_DIR="/opt/streamforge"
SERVICE_USER="streamforge"

echo -e "\n${YW}StreamForge Updater${CL}\n"

msg_info "Stopping StreamForge"
systemctl stop streamforge
msg_ok "Stopped"

msg_info "Updating server (index.js)"
echo '' | base64 -d > "$INSTALL_DIR/server/index.js"
msg_ok "index.js updated"

msg_info "Updating server (package.json)"
echo '' | base64 -d > "$INSTALL_DIR/server/package.json"
msg_ok "package.json updated"

msg_info "Updating frontend (index.html)"
echo '' | base64 -d > "$INSTALL_DIR/public/index.html"
msg_ok "index.html updated"

msg_info "Updating styles (main.css)"
echo '' | base64 -d > "$INSTALL_DIR/public/css/main.css"
msg_ok "main.css updated"

msg_info "Updating app logic (app.js)"
echo '' | base64 -d > "$INSTALL_DIR/public/js/app.js"
msg_ok "app.js updated"

msg_info "Fixing ownership"
chown -R "$SERVICE_USER:$SERVICE_USER" "$INSTALL_DIR"
msg_ok "Ownership fixed"

msg_info "Updating npm dependencies"
cd "$INSTALL_DIR/server"
su -s /bin/bash "$SERVICE_USER" -c "cd $INSTALL_DIR/server && npm install --production --quiet"
msg_ok "npm updated"

msg_info "Starting StreamForge"
systemctl start streamforge
sleep 3
if systemctl is-active --quiet streamforge; then
  msg_ok "StreamForge is running"
else
  echo -e "\n${RD}Failed to start — logs:${CL}"
  journalctl -u streamforge -n 20 --no-pager
  exit 1
fi

echo ""
echo -e "${GN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${CL}"
echo -e "${GN}  StreamForge updated successfully!${CL}"
echo -e "${GN}━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━${CL}"
echo ""
echo "IMPORTANT: Re-scan your Plex library to update stream URLs"
echo "  Libraries → ↻ Scan"
echo ""
journalctl -u streamforge -n 6 --no-pager
echo ""
